import { describe, expect, it } from 'vitest';

import {
  AMPLITUHEDRON_CONTENT_TYPE,
  encodeReplayResponse,
  decodeCaptureRequest,
} from '../src/amplituhedron-wire';
import { Station } from '../src/station';

interface RecordedCall {
  url: string;
  method: string;
  headers: Record<string, string>;
  body: ArrayBuffer;
}

/** Minimal recording fetcher that satisfies StationEndpoint. */
function makeFetcher(
  handler: (call: RecordedCall) => Response | Promise<Response>
) {
  const calls: RecordedCall[] = [];
  return {
    calls,
    fetch: async (req: Request) => {
      const body = await req.arrayBuffer();
      const headers: Record<string, string> = {};
      req.headers.forEach((v, k) => {
        headers[k.toLowerCase()] = v;
      });
      const call: RecordedCall = {
        url: req.url,
        method: req.method,
        headers,
        body,
      };
      calls.push(call);
      return handler(call);
    },
  };
}

function f32Body(arr: Float32Array): ArrayBuffer {
  const buf = new ArrayBuffer(arr.byteLength);
  new Uint8Array(buf).set(
    new Uint8Array(arr.buffer, arr.byteOffset, arr.byteLength)
  );
  return buf;
}

describe('Station construction', () => {
  it('rejects non-integer or negative startLayer', () => {
    const ep = { fetch: async () => new Response() };
    expect(
      () => new Station({ endpoint: ep, startLayer: -1, endLayer: 1 })
    ).toThrow();
    expect(
      () => new Station({ endpoint: ep, startLayer: 1.5, endLayer: 2 })
    ).toThrow();
  });

  it('rejects endLayer < startLayer', () => {
    const ep = { fetch: async () => new Response() };
    expect(
      () => new Station({ endpoint: ep, startLayer: 4, endLayer: 2 })
    ).toThrow();
  });

  it('exposes startLayer, endLayer, role', () => {
    const ep = { fetch: async () => new Response() };
    const s = new Station({
      endpoint: ep,
      startLayer: 0,
      endLayer: 8,
      role: 'entry',
    });
    expect(s.startLayer).toBe(0);
    expect(s.endLayer).toBe(8);
    expect(s.role).toBe('entry');
  });
});

describe('Station.forward', () => {
  it('POSTs Float32Array body with X-Position, X-Sequence-Length, X-Layer-Range headers', async () => {
    const reply = new Float32Array([0.1, 0.2, 0.3, 0.4]);
    const f = makeFetcher(() => new Response(f32Body(reply)));
    const s = new Station({
      endpoint: f,
      startLayer: 4,
      endLayer: 12,
      baseUrl: 'http://test',
    });
    const out = await s.forward({
      residual: new Float32Array([1, 2, 3, 4]),
      startPos: 17,
      sequenceLength: 1,
      requestId: 'req-abc',
    });
    expect(f.calls).toHaveLength(1);
    expect(f.calls[0]!.method).toBe('POST');
    expect(f.calls[0]!.url).toBe('http://test/forward');
    expect(f.calls[0]!.headers['x-position']).toBe('17');
    expect(f.calls[0]!.headers['x-sequence-length']).toBe('1');
    expect(f.calls[0]!.headers['x-layer-range']).toBe('4-12');
    expect(f.calls[0]!.headers['x-request-id']).toBe('req-abc');
    expect(new Float32Array(f.calls[0]!.body)).toEqual(
      new Float32Array([1, 2, 3, 4])
    );
    expect(Array.from(out.residual)).toEqual(
      [0.1, 0.2, 0.3, 0.4].map((v) => Math.fround(v))
    );
  });

  it('rejects sequenceLength <= 0', async () => {
    const f = makeFetcher(() => new Response());
    const s = new Station({ endpoint: f, startLayer: 0, endLayer: 4 });
    await expect(
      s.forward({
        residual: new Float32Array(4),
        startPos: 0,
        sequenceLength: 0,
      })
    ).rejects.toThrow(/sequenceLength/);
  });

  it('rejects negative startPos', async () => {
    const f = makeFetcher(() => new Response());
    const s = new Station({ endpoint: f, startLayer: 0, endLayer: 4 });
    await expect(
      s.forward({
        residual: new Float32Array(4),
        startPos: -1,
        sequenceLength: 1,
      })
    ).rejects.toThrow(/startPos/);
  });

  it('throws on non-OK response with body detail', async () => {
    const f = makeFetcher(() => new Response('boom', { status: 500 }));
    const s = new Station({ endpoint: f, startLayer: 0, endLayer: 4 });
    await expect(
      s.forward({
        residual: new Float32Array(4),
        startPos: 0,
        sequenceLength: 1,
      })
    ).rejects.toThrow(/HTTP 500.*boom/);
  });

  it('throws when response byteLength is not a multiple of 4', async () => {
    const f = makeFetcher(() => new Response(new ArrayBuffer(7)));
    const s = new Station({ endpoint: f, startLayer: 0, endLayer: 4 });
    await expect(
      s.forward({
        residual: new Float32Array(4),
        startPos: 0,
        sequenceLength: 1,
      })
    ).rejects.toThrow(/multiple of 4/);
  });
});

describe('Station.embed', () => {
  it('POSTs Uint32Array tokens to /embed and parses Float32Array reply', async () => {
    const reply = new Float32Array([1, 2, 3, 4, 5, 6]);
    const f = makeFetcher(() => new Response(f32Body(reply)));
    const s = new Station({
      endpoint: f,
      startLayer: 0,
      endLayer: 8,
      role: 'entry',
      baseUrl: 'http://test',
    });
    const out = await s.embed({
      tokens: new Uint32Array([10, 20, 30]),
      startPos: 0,
    });
    expect(f.calls[0]!.url).toBe('http://test/embed');
    expect(f.calls[0]!.headers['x-token-count']).toBe('3');
    expect(new Uint32Array(f.calls[0]!.body)).toEqual(
      new Uint32Array([10, 20, 30])
    );
    expect(out.length).toBe(6);
  });

  it('refuses to embed when role is not entry', async () => {
    const f = makeFetcher(() => new Response());
    const s = new Station({
      endpoint: f,
      startLayer: 0,
      endLayer: 4,
      role: 'mid',
    });
    await expect(
      s.embed({ tokens: new Uint32Array([1]), startPos: 0 })
    ).rejects.toThrow(/entry/);
  });
});

describe('Station.lmHead', () => {
  it('POSTs residual to /lm-head and parses Float32Array logits', async () => {
    const reply = new Float32Array(32);
    reply[7] = 99;
    const f = makeFetcher(() => new Response(f32Body(reply)));
    const s = new Station({
      endpoint: f,
      startLayer: 24,
      endLayer: 32,
      role: 'exit',
      baseUrl: 'http://test',
    });
    const logits = await s.lmHead({
      residual: new Float32Array(8),
      sequenceLength: 1,
    });
    expect(f.calls[0]!.url).toBe('http://test/lm-head');
    expect(f.calls[0]!.headers['x-sequence-length']).toBe('1');
    expect(logits[7]).toBe(99);
  });

  it('applies Ackermann admission before /lm-head dispatch', async () => {
    const reply = new Float32Array(4);
    const f = makeFetcher(() => new Response(f32Body(reply)));
    const s = new Station({
      endpoint: f,
      startLayer: 24,
      endLayer: 32,
      role: 'exit',
      baseUrl: 'http://test',
    });
    await s.lmHead({
      residual: new Float32Array(8),
      sequenceLength: 1,
      ackermannAdmission: {
        projection: { waste: 1, opportunity: 1, diversity: 1, score: 3 },
        replicas: 2,
        ceiling: 12,
      },
    });
    expect(f.calls[0]!.headers['x-ackermann-admission']).toBe('admitted');
    expect(f.calls[0]!.headers['x-ackermann-heat']).toBe('6');
  });

  it('rejects failed Ackermann admission without dispatching /lm-head', async () => {
    const f = makeFetcher(() => new Response(f32Body(new Float32Array(4))));
    const s = new Station({
      endpoint: f,
      startLayer: 24,
      endLayer: 32,
      role: 'exit',
      baseUrl: 'http://test',
    });
    await expect(
      s.lmHead({
        residual: new Float32Array(8),
        sequenceLength: 1,
        ackermannAdmission: {
          projection: { waste: 4, opportunity: 4, diversity: 4, score: 12 },
          replicas: 2,
          ceiling: 12,
        },
      })
    ).rejects.toThrow(/Hot Replica rejected/);
    expect(f.calls).toHaveLength(0);
  });

  it('refuses to lm_head when role is not exit', async () => {
    const f = makeFetcher(() => new Response());
    const s = new Station({
      endpoint: f,
      startLayer: 0,
      endLayer: 4,
      role: 'entry',
    });
    await expect(
      s.lmHead({ residual: new Float32Array(4), sequenceLength: 1 })
    ).rejects.toThrow(/exit/);
  });
});

describe('Station.encodeStreamingChunk', () => {
  it('POSTs a mel chunk to /encode-streaming with chunk metadata', async () => {
    const reply = new Float32Array([0.25, 0.5, 0.75, 1]);
    const f = makeFetcher(() => new Response(f32Body(reply)));
    const s = new Station({
      endpoint: f,
      startLayer: 0,
      endLayer: 4,
      baseUrl: 'http://test',
    });

    const out = await s.encodeStreamingChunk({
      melChunk: new Float32Array([1, 2, 3, 4]),
      chunkIndex: 2,
      requestId: 'req-stream',
    });

    expect(f.calls).toHaveLength(1);
    expect(f.calls[0]!.method).toBe('POST');
    expect(f.calls[0]!.url).toBe('http://test/encode-streaming');
    expect(f.calls[0]!.headers['x-chunk-index']).toBe('2');
    expect(f.calls[0]!.headers['x-layer-range']).toBe('0-4');
    expect(f.calls[0]!.headers['x-request-id']).toBe('req-stream');
    expect(new Float32Array(f.calls[0]!.body)).toEqual(
      new Float32Array([1, 2, 3, 4])
    );
    expect(Array.from(out)).toEqual([0.25, 0.5, 0.75, 1]);
  });

  it('rejects negative chunk indexes before dispatch', async () => {
    const f = makeFetcher(() => new Response());
    const s = new Station({ endpoint: f, startLayer: 0, endLayer: 4 });

    await expect(
      s.encodeStreamingChunk({
        melChunk: new Float32Array([1, 2]),
        chunkIndex: -1,
      })
    ).rejects.toThrow(/chunkIndex/);
    expect(f.calls).toHaveLength(0);
  });
});

describe('Station amplituhedron admin path', () => {
  it('POSTs JSON to /amplituhedron/replay and decodes a bitwise hit envelope', async () => {
    const tail = new Float32Array([0.25, 0.5, 0.75, 1]);
    const prefix = new Float32Array([1, 2, 3, 4, 5, 6, 7, 8]);
    const replayBytes = encodeReplayResponse({
      hit: true,
      tailLen: tail.length,
      kvSlabLen: 0,
      tailResidual: tail,
      prefixResidualLen: prefix.length,
      prefixResidual: prefix,
    });
    const f = makeFetcher(
      () =>
        new Response(
          replayBytes.buffer.slice(
            replayBytes.byteOffset,
            replayBytes.byteOffset + replayBytes.byteLength,
          ) as ArrayBuffer,
          {
            status: 200,
            headers: { 'Content-Type': AMPLITUHEDRON_CONTENT_TYPE },
          }
        )
    );
    const s = new Station({
      endpoint: f,
      startLayer: 0,
      endLayer: 8,
      baseUrl: 'http://test',
    });

    // Synthetic decimal u64 fixture — codec requires decimal u64 strings
    // (matches prefixHashU64 production output in pipeline.ts).
    const result = await s.amplituhedronReplay({
      prefixHash: '3735928559',
      prefixLen: 17,
      layerLo: 0,
      layerHi: 8,
      requestId: 'req-amph-1',
    });

    expect(f.calls).toHaveLength(1);
    expect(f.calls[0]!.method).toBe('POST');
    expect(f.calls[0]!.url).toBe('http://test/amplituhedron/replay');
    expect(f.calls[0]!.headers['content-type']).toBe('application/json');
    expect(f.calls[0]!.headers['accept']).toBe(AMPLITUHEDRON_CONTENT_TYPE);
    const sentJson = JSON.parse(
      new TextDecoder().decode(f.calls[0]!.body)
    ) as Record<string, unknown>;
    expect(sentJson['prefix_hash']).toBe('3735928559');
    expect(sentJson['prefix_len']).toBe(17);
    expect(sentJson['layer_lo']).toBe(0);
    expect(sentJson['layer_hi']).toBe(8);
    expect(sentJson['request_id']).toBe('req-amph-1');
    expect(result.hit).toBe(true);
    expect(Array.from(result.tailResidual ?? new Float32Array())).toEqual([
      0.25, 0.5, 0.75, 1,
    ]);
    expect(Array.from(result.prefixResidual ?? new Float32Array())).toEqual([
      1, 2, 3, 4, 5, 6, 7, 8,
    ]);
    expect(result.tailFingerprint).toMatch(/^[0-9a-f]{16}$/);
    expect(result.prefixFingerprint).toMatch(/^[0-9a-f]{16}$/);
  });

  it('treats 204 No Content as a clean miss', async () => {
    const f = makeFetcher(() => new Response(null, { status: 204 }));
    const s = new Station({
      endpoint: f,
      startLayer: 0,
      endLayer: 8,
      baseUrl: 'http://test',
    });

    const result = await s.amplituhedronReplay({
      prefixHash: '1111111111',
      prefixLen: 1,
      layerLo: 0,
      layerHi: 8,
    });
    expect(result.hit).toBe(false);
    expect(result.tailResidual).toBeUndefined();
  });

  it('returns hit:false defensively on a 500 — never throws on replay path', async () => {
    const f = makeFetcher(() => new Response('boom', { status: 500 }));
    const s = new Station({
      endpoint: f,
      startLayer: 0,
      endLayer: 8,
      baseUrl: 'http://test',
    });

    const result = await s.amplituhedronReplay({
      prefixHash: '9999999999',
      prefixLen: 1,
      layerLo: 0,
      layerHi: 8,
    });
    expect(result.hit).toBe(false);
  });

  it('POSTs bitwise tail_residual to /amplituhedron/capture and resolves void', async () => {
    const f = makeFetcher(() => new Response('{"captured":true}', { status: 200 }));
    const s = new Station({
      endpoint: f,
      startLayer: 0,
      endLayer: 8,
      baseUrl: 'http://test',
    });

    await s.amplituhedronCapture({
      prefixHash: '4242424242',
      prefixLen: 22,
      layerLo: 0,
      layerHi: 8,
      tailResidual: new Float32Array([1.5, 2.5, 3.5]),
      requestId: 'req-capture-1',
    });

    expect(f.calls).toHaveLength(1);
    expect(f.calls[0]!.url).toBe('http://test/amplituhedron/capture');
    const decoded = decodeCaptureRequest(
      new Uint8Array(f.calls[0]!.body)
    );
    expect(decoded.prefixHash).toBe('4242424242');
    expect(decoded.prefixLen).toBe(22);
    expect(decoded.layerLo).toBe(0);
    expect(decoded.layerHi).toBe(8);
    expect(Array.from(decoded.tailResidual ?? new Float32Array())).toEqual([
      1.5, 2.5, 3.5,
    ]);
  });

  it('capture swallows server errors — never throws on best-effort path', async () => {
    const f = makeFetcher(() => new Response('nope', { status: 500 }));
    const s = new Station({
      endpoint: f,
      startLayer: 0,
      endLayer: 8,
      baseUrl: 'http://test',
    });

    await expect(
      s.amplituhedronCapture({
        prefixHash: '9999999999',
        prefixLen: 1,
        layerLo: 0,
        layerHi: 8,
      })
    ).resolves.toBeUndefined();
  });

  it('replay sets Accept and capture sets Content-Type to application/x-bitwise-residual', async () => {
    // Replay: Accept must announce the bitwise wire.
    const replayFetcher = makeFetcher(() => new Response(null, { status: 204 }));
    const replayStation = new Station({
      endpoint: replayFetcher,
      startLayer: 0,
      endLayer: 8,
      baseUrl: 'http://test',
    });
    await replayStation.amplituhedronReplay({
      prefixHash: '8888888888',
      prefixLen: 1,
      layerLo: 0,
      layerHi: 8,
    });
    expect(replayFetcher.calls[0]!.headers['accept']).toBe(
      AMPLITUHEDRON_CONTENT_TYPE
    );

    // Capture: Content-Type must declare the bitwise wire.
    const captureFetcher = makeFetcher(() => new Response('', { status: 200 }));
    const captureStation = new Station({
      endpoint: captureFetcher,
      startLayer: 0,
      endLayer: 8,
      baseUrl: 'http://test',
    });
    await captureStation.amplituhedronCapture({
      prefixHash: '8888888888',
      prefixLen: 1,
      layerLo: 0,
      layerHi: 8,
      tailResidual: new Float32Array([1, 2]),
    });
    expect(captureFetcher.calls[0]!.headers['content-type']).toBe(
      AMPLITUHEDRON_CONTENT_TYPE
    );
  });
});
